// // This module decrements a 4-bit counter on each clock cycle.
module counter_4bit(
    input clk, rst,
    output reg [3:0] count);

    always @(posedge clk or posedge rst) begin
        if (rst)
            count <= 4'b0000;
        else
            count <= count + 1;
    end
endmodule
